-- 테이블 pos35.alloc_vehicles 구조 내보내기
CREATE TABLE IF NOT EXISTS `alloc_vehicles` (
  `allocid` int(10) unsigned NOT NULL AUTO_INCREMENT COMMENT '접수 번호',
  `clientid` int(10) unsigned DEFAULT 0 COMMENT '고객 고유 번호',
  `drvseq` int(10) unsigned DEFAULT 0 COMMENT '기사 고유 번호',
  `call_date` datetime DEFAULT '0000-00-00 00:00:00' COMMENT '호출 일시',
  `call_address1` varchar(50) DEFAULT '' COMMENT '호출지명',
  `call_address2` varchar(50) DEFAULT '' COMMENT '호출지 주소',
  `call_address3` varchar(50) DEFAULT '' COMMENT '목적지명',
  `xpos` int(10) unsigned DEFAULT 0 COMMENT '호출지 X좌표 (경도)',
  `ypos` int(10) unsigned DEFAULT 0 COMMENT '호출지 Y좌표 (위도)',
  `dest_xpos` int(10) unsigned DEFAULT 0 COMMENT '목적지 X좌표',
  `dest_ypos` int(10) unsigned DEFAULT 0 COMMENT '목적지 Y좌표',
  `call_state` tinyint(4) DEFAULT 0 COMMENT '배차 상태',
  `call_process` tinyint(4) DEFAULT 1 COMMENT '배차 단계',
  `send_level` tinyint(4) DEFAULT 0 COMMENT '검색 단계',
  `opname` char(12) DEFAULT '' COMMENT '접수 상담원',
  `send_time` datetime DEFAULT '0000-00-00 00:00:00' COMMENT '배차 내용 전송 시간(to 기사)',
  `recv_time` datetime DEFAULT '0000-00-00 00:00:00' COMMENT '배차 내용 응답 시간(from 기사)',
  `repeat_time` datetime DEFAULT '0000-00-00 00:00:00' COMMENT '검색 반복 시작 시간',
  `card_type` tinyint(4) DEFAULT 0 COMMENT '카드 종류',
  `cancel_type` tinyint(4) DEFAULT 0 COMMENT '취소 유형',
  `return_flag` tinyint(4) DEFAULT 0 COMMENT '왕복 flag',
  `drv_distance` smallint(5) unsigned DEFAULT 0 COMMENT '예상 거리',
  `drv_cash` smallint(5) unsigned DEFAULT 0 COMMENT '예상 금액',
  `drv_addedcash` smallint(5) unsigned DEFAULT 0 COMMENT '예상 추가 금액',
  `payments` tinyint(4) DEFAULT 0 COMMENT '결제 유형',
  `req_call_state` tinyint(4) DEFAULT 0 COMMENT '배차 방식',
  `board_time` datetime DEFAULT '0000-00-00 00:00:00' COMMENT '승차 시간',
  `leave_time` datetime DEFAULT '0000-00-00 00:00:00' COMMENT '하차 시간',
  `agent_alloc_cnt` smallint(5) DEFAULT 0 COMMENT '검색 반복 수',
  `safe` tinyint(4) unsigned DEFAULT 0 COMMENT '안심 귀가 서비스 여부',
  `driving_alloc` tinyint(4) unsigned DEFAULT 0 COMMENT '기타',
  `citycode0` int(10) unsigned DEFAULT 0 COMMENT '기타',
  `citycode1` int(10) unsigned DEFAULT 0 COMMENT '기타',
  `citycode2` int(10) unsigned DEFAULT 0 COMMENT '시내/시외 여부',
  `citycode3` int(10) unsigned DEFAULT 0 COMMENT '법인 예비기사의 경우 car_info의 차량정보는 여기에 저장한다.',
  `customer_call_fail` tinyint(1) DEFAULT 0 COMMENT '기타 접수 취소 코드',
  `vehproblem` tinyint(1) unsigned DEFAULT 0 COMMENT '차량 문제 발생 코드',
  `local_idx` tinyint(3) unsigned DEFAULT 0 COMMENT '지역 번호',
  `ClientType` tinyint(3) unsigned DEFAULT 0 COMMENT 'Client_Type테이블 키값',
  `av_carno` char(32) DEFAULT NULL COMMENT '차량 번호',
  PRIMARY KEY (`allocid`),
  KEY `call_date` (`call_date`,`clientid`,`drvseq`),
  KEY `clientid` (`clientid`,`drvseq`),
  KEY `clientid_call_date` (`clientid`,`call_date`)
) ENGINE=InnoDB AUTO_INCREMENT=14958022 DEFAULT CHARSET=euckr ROW_FORMAT=COMPACT COMMENT='접수 데이터';

